class FakeCliB2Client:
    def __init__(self, *, object_prefix: str = "ace-attest", instance_id: str = "andrew-prod") -> None:
        self.config = B2Config(
            key_id="redacted-key",
            application_key="redacted-app",
            bucket="ace-bucket",
            instance_id=instance_id,
            object_prefix=object_prefix,
        )
        self.objects: dict[str, bytes] = {}
        self.versions: dict[str, list[B2ObjectVersion]] = {}
        self.upload_calls: list[str] = []
        self.list_prefix_calls: list[str] = []

    def list_prefix(self, prefix: str) -> list[B2Object]:
        self.list_prefix_calls.append(prefix)
        return [
            B2Object(file_name=name, file_id=self.versions[name][0].file_id if self.versions.get(name) else f"id-{name}")
            for name in sorted(self.objects)
            if name.startswith(prefix)
        ]

    def list_versions(self, prefix: str) -> list[B2ObjectVersion]:
        versions: list[B2ObjectVersion] = []
        for name, name_versions in self.versions.items():
            if name.startswith(prefix):
                versions.extend(name_versions)
        return versions

    def read_object(self, file_name: str) -> bytes:
        return self.objects[file_name]

    def upload_if_absent(self, file_name: str, content: bytes, *, content_type: str = "application/json") -> B2Object:
        self.upload_calls.append(file_name)
        self.objects[file_name] = content
        self.versions[file_name] = [
            B2ObjectVersion(
                file_name=file_name,
                file_id=f"id-{len(self.upload_calls)}",
                action="upload",
                upload_timestamp=len(self.upload_calls),
                content_sha1=hashlib.sha1(content).hexdigest(),
                size=len(content),
            )
        ]
        return B2Object(file_name=file_name, file_id=f"id-{len(self.upload_calls)}", size=len(content), content_sha1=hashlib.sha1(content).hexdigest())

    def seed_expected(self, db_path: Path) -> list:
        expected = expected_attestation_objects(
            db_path,
            instance_id=self.config.instance_id,
            object_prefix=self.config.object_prefix,
        )
        for index, item in enumerate(expected, start=1):
            self.objects[item.file_name] = item.body
            self.versions[item.file_name] = [
                B2ObjectVersion(
                    file_name=item.file_name,
                    file_id=f"id-{index}",
                    action="upload",
                    upload_timestamp=index,
                    content_sha1=hashlib.sha1(item.body).hexdigest(),
                    size=len(item.body),
                )
            ]
        return expected


class AceCliParserContractTests(unittest.TestCase):
    def run_cli(self, *argv: str) -> tuple[int, str]:
        buffer = io.StringIO()
        with redirect_stdout(buffer):
            code = main(list(argv))
        return code, buffer.getvalue()

    def test_main_without_command_bootstraps_default_db_path(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "default.db"
            original_db_path = Path(main.__globals__["DB_PATH"])
            main.__globals__["DB_PATH"] = db_path
            try:
                code, output = self.run_cli()
            finally:
                main.__globals__["DB_PATH"] = original_db_path
            self.assertEqual(code, 0, output)
            self.assertIn(f"Initialized ACE state at {db_path}", output)
            self.assertTrue(db_path.exists())

    def test_init_command_bootstraps_requested_db_path(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "init.db"
            code, output = self.run_cli("--db", str(db_path), "init")
            self.assertEqual(code, 0, output)
            self.assertIn(f"Initialized ACE state at {db_path}", output)
            self.assertTrue(db_path.exists())

    def test_bootstrap_command_is_alias_for_init(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "bootstrap.db"
            code, output = self.run_cli("--db", str(db_path), "bootstrap")
            self.assertEqual(code, 0, output)
            self.assertIn(f"Initialized ACE state at {db_path}", output)
            self.assertTrue(db_path.exists())

    def test_invalid_subcommand_exits_via_argparse(self) -> None:
        stderr = io.StringIO()
        with self.assertRaises(SystemExit) as exc, redirect_stderr(stderr):
            main(["definitely-not-a-command"])
        self.assertEqual(exc.exception.code, 2)
        self.assertIn("invalid choice", stderr.getvalue())

    def test_missing_required_arguments_exit_via_argparse(self) -> None:
        stderr = io.StringIO()
        with self.assertRaises(SystemExit) as exc, redirect_stderr(stderr):
            main(["intake", "note"])
        self.assertEqual(exc.exception.code, 2)
        self.assertIn("the following arguments are required: title", stderr.getvalue())


class AceCliStaleTests(unittest.TestCase):
    def run_cli(self, *argv: str) -> tuple[int, str]:
        buffer = io.StringIO()
        with redirect_stdout(buffer):
            code = main(list(argv))
        return code, buffer.getvalue()

    def test_stale_lists_idle_open_items_sorted_by_days_idle_descending(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"
            bootstrap_db(db_path)
            now = datetime.now(timezone.utc)
            with closing(sqlite3.connect(db_path)) as connection:
                connection.row_factory = sqlite3.Row
                items = [
                    ("item_very_old", "task", "Very old", "ACTIVE", (now - timedelta(days=14, hours=2)).isoformat().replace("+00:00", "Z"), "item.touched"),
                    ("item_recent", "task", "Recent", "ACTIVE", (now - timedelta(days=2)).isoformat().replace("+00:00", "Z"), "item.touched"),
                    ("item_old", "task", "Old", "TRIAGE", (now - timedelta(days=8, minutes=5)).isoformat().replace("+00:00", "Z"), "item.created"),
                ]
                for item_id, item_type, title, state, created_at, event_type in items:
                    event_id = f"evt_{item_id}"
                    connection.execute(
                        """
                        INSERT INTO items (
                            id, item_type, title, state, created_at, updated_at, last_event_id
                        ) VALUES (?, ?, ?, ?, ?, ?, ?)
                        """,
                        (item_id, item_type, title, state, created_at, created_at, event_id),
                    )
                    connection.execute(
                        """
                        INSERT INTO events (
                            event_id, item_id, event_type, payload_json, created_at, event_hash
                        ) VALUES (?, ?, ?, ?, ?, ?)
                        """,
                        (event_id, item_id, event_type, "{}", created_at, "0" * 64),
                    )
                connection.commit()

            code, output = self.run_cli("--db", str(db_path), "stale", "--days", "7")

            self.assertEqual(code, 0, output)
            lines = output.strip().splitlines()
            self.assertEqual(lines[0], "item_id                              current_state  days_idle last_event_type                 ")
            self.assertIn("item_very_old", lines[1])
            self.assertIn("ACTIVE", lines[1])
            self.assertIn("item.touched", lines[1])
            self.assertIn("item_old", lines[2])
            self.assertIn("TRIAGE", lines[2])
            self.assertIn("item.created", lines[2])
            self.assertNotIn("item_recent", output)

    def test_stale_uses_last_event_timestamp_even_when_item_updated_at_is_newer(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"
            bootstrap_db(db_path)
            old_event_at = (datetime.now(timezone.utc) - timedelta(days=9)).isoformat().replace("+00:00", "Z")
            newer_updated_at = datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")
            with closing(sqlite3.connect(db_path)) as connection:
                connection.execute(
                    "INSERT INTO items (id, item_type, title, state, created_at, updated_at, last_event_id) VALUES (?, ?, ?, ?, ?, ?, ?)",
                    ("item_last_event_old", "task", "Old event", "ACTIVE", old_event_at, newer_updated_at, "evt_last_event_old"),
                )
                connection.execute(
                    "INSERT INTO events (event_id, item_id, event_type, payload_json, created_at, event_hash) VALUES (?, ?, ?, ?, ?, ?)",
                    ("evt_last_event_old", "item_last_event_old", "item.state_changed", "{}", old_event_at, "0" * 64),
                )
                connection.commit()

            code, output = self.run_cli("--db", str(db_path), "stale", "--days", "7")

            self.assertEqual(code, 0, output)
            self.assertIn("item_last_event_old", output)
            self.assertIn("item.state_changed", output)

    def test_stale_default_threshold_is_seven_days(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"
            bootstrap_db(db_path)
            old_at = (datetime.now(timezone.utc) - timedelta(days=7, hours=1)).isoformat().replace("+00:00", "Z")
            recent_at = (datetime.now(timezone.utc) - timedelta(days=6, hours=23)).isoformat().replace("+00:00", "Z")
            with closing(sqlite3.connect(db_path)) as connection:
                connection.execute(
                    "INSERT INTO items (id, item_type, title, state, created_at, updated_at, last_event_id) VALUES (?, ?, ?, ?, ?, ?, ?)",
                    ("item_old", "task", "Old", "ACTIVE", old_at, old_at, "evt_old"),
                )
                connection.execute(
                    "INSERT INTO events (event_id, item_id, event_type, payload_json, created_at, event_hash) VALUES (?, ?, ?, ?, ?, ?)",
                    ("evt_old", "item_old", "item.touched", "{}", old_at, "0" * 64),
                )
                connection.execute(
                    "INSERT INTO items (id, item_type, title, state, created_at, updated_at, last_event_id) VALUES (?, ?, ?, ?, ?, ?, ?)",
                    ("item_recent", "task", "Recent", "ACTIVE", recent_at, recent_at, "evt_recent"),
                )
                connection.execute(
                    "INSERT INTO events (event_id, item_id, event_type, payload_json, created_at, event_hash) VALUES (?, ?, ?, ?, ?, ?)",
                    ("evt_recent", "item_recent", "item.touched", "{}", recent_at, "0" * 64),
                )
                connection.commit()

            code, output = self.run_cli("--db", str(db_path), "stale")

            self.assertEqual(code, 0, output)
            self.assertIn("item_old", output)
            self.assertNotIn("item_recent", output)

    def test_stale_rejects_negative_days(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"
            bootstrap_db(db_path)

            code, output = self.run_cli("--db", str(db_path), "stale", "--days", "-1")

            self.assertEqual(code, 1, output)
            self.assertEqual(output.strip(), "error=days must be greater than or equal to 0")

    def test_stale_does_not_bootstrap_missing_database(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "missing.db"

            with self.assertRaises(sqlite3.OperationalError):
                self.run_cli("--db", str(db_path), "stale")

            self.assertFalse(db_path.exists())


class AceCliTests(unittest.TestCase):
    class _ManagedConnection:
        def __init__(self, connection: sqlite3.Connection) -> None:
            self._connection = connection

        def __getattr__(self, name: str):
            return getattr(self._connection, name)

        def execute(self, sql: str, parameters=(), /):
            if isinstance(sql, str) and "INSERT INTO events" in sql:
                statement = sql
                values_marker = ") VALUES"
                normalized = " ".join(statement.split())
                if "event_hash" not in normalized:
                    statement = re.sub(r"\)\s*VALUES", ", event_hash, event_sequence) VALUES", statement, count=1, flags=re.IGNORECASE)
                    values_tail = statement.rfind(")")
                    statement = statement[:values_tail] + ", ?, ?" + statement[values_tail:]
                    parameters = tuple(parameters) + ("0" * 64, 1)
                _enable_event_insert(self._connection)
                try:
                    return self._connection.execute(statement, parameters)
                finally:
                    _disable_event_insert(self._connection)
            return self._connection.execute(sql, parameters)

        def __enter__(self):
            self._connection.__enter__()
            return self

        def __exit__(self, exc_type, exc, tb):
            try:
                return self._connection.__exit__(exc_type, exc, tb)
            finally:
                self._connection.close()

        def close(self) -> None:
            self._connection.close()

    def run_cli(self, *argv: str) -> tuple[int, str]:
        buffer = io.StringIO()
        with redirect_stdout(buffer):
            code = main(list(argv))
        return code, buffer.getvalue()

    def connect_db(self, db_path: Path):
        connection = sqlite3.connect(db_path)
        connection.row_factory = sqlite3.Row
        return self._ManagedConnection(connection)

    def _build_post_cutover_chain(self, db_path: Path, post_events: int = 2) -> None:
        bootstrap_db(db_path)
        with connect(db_path) as connection:
            append_event(connection, event_type="item.legacy", payload={"legacy": True})
            append_cutover_genesis_event(
                connection,
                authorization_token=CUTOVER_EXECUTE_AUTHORIZATION_TOKEN,
                governing_decision_reference="test approval",
                actor="test",
                source="ace/tests/test_cli.py",
                session_id="v1.1-cutover:test",
            )
            for index in range(post_events):
                append_event(connection, event_type="item.post", payload={"index": index})
            connection.commit()


    def test_audit_verify_reports_valid_integrity_checks(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"
            code, output = self.run_cli("--db", str(db_path), "intake", "task", "Audit verify item")
            self.assertEqual(code, 0, output)

            code, output = self.run_cli("--db", str(db_path), "audit", "verify")

            self.assertEqual(code, 2, output)
            self.assertIn("audit.verify.legacy_chain_inventory=ok", output)
            self.assertIn("audit.verify.legacy_chain_inventory_detail=legacy_chain_inventory=pre_cutover disclosure_present=true cutover_event=absent", output)
            self.assertIn("audit.verify.event_hash_chain=ok", output)
            self.assertIn("audit.verify.post_cutover_event_hash_chain=ok", output)
            self.assertIn("audit.verify.post_cutover_event_hash_chain_detail=post_cutover_event_hash_chain=not_started cutover_event=absent", output)
            self.assertIn("audit.verify.evidence_consistency=ok", output)
            self.assertIn("audit.verify.governed_run_integrity=ok", output)
            self.assertIn("audit.verify.runtime_instance_integrity=ok", output)
            self.assertIn("audit.verify.external_attestation=failed", output)
            self.assertIn("external_attestation_not_configured", output)
            self.assertIn(f"audit.verify.db_path={db_path}", output)

    def test_audit_verify_returns_nonzero_when_integrity_check_fails(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"
            self.run_cli("--db", str(db_path), "intake", "task", "Audit verify broken evidence")
            with self.connect_db(db_path) as connection:
                connection.execute("PRAGMA foreign_keys = OFF")
                connection.execute(
                    """
                    INSERT INTO evidence (id, item_id, evidence_text, created_at)
                    VALUES (?, ?, ?, ?)
                    """,
                    ("evidence_orphan_item", "missing_item", "orphan proof", "2026-05-15T00:00:00Z"),
                )
                connection.commit()

            code, output = self.run_cli("--db", str(db_path), "audit", "verify")

            self.assertEqual(code, 1, output)
            self.assertIn("audit.verify.legacy_chain_inventory=ok", output)
            self.assertIn("audit.verify.event_hash_chain=ok", output)
            self.assertIn("audit.verify.post_cutover_event_hash_chain=ok", output)
            self.assertIn("audit.verify.evidence_consistency=failed", output)
            self.assertIn("audit.verify.governed_run_integrity=ok", output)
            self.assertIn("audit.verify.runtime_instance_integrity=ok", output)
            self.assertIn("audit.verify.reason=evidence evidence_orphan_item references missing item missing_item", output)

