    def test_show_trimmed_event_type_with_limit_one_preserves_malformed_latest_matching_event(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"

            bootstrap_db(db_path)
            item_id = str(uuid4())
            with closing(self.connect_db(db_path)) as connection:
                connection.execute(
                    "INSERT INTO items (id, item_type, title, state, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)",
                    (
                        item_id,
                        "note",
                        "Trimmed malformed latest selector item",
                        "TRIAGE",
                        utc_now(),
                        utc_now(),
                    ),
                )
                append_event(
                    connection,
                    item_id=item_id,
                    event_type="item.evidence_added",
                    payload={"evidence_text": "proof one"},
                )
                append_event(
                    connection,
                    item_id=item_id,
                    event_type="item.obligation_added",
                    payload={"obligation_type": "review"},
                )
                connection.execute(
                    "INSERT INTO events (event_id, item_id, event_type, payload_json, actor, source, session_id, created_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
                    (
                        str(uuid4()),
                        item_id,
                        "item.evidence_added",
                        '{"broken":',
                        None,
                        None,
                        None,
                        utc_now(),
                    ),
                )
                connection.commit()

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "show",
                item_id,
                "--event-type",
                "\titem.evidence_added\n",
                "--event-limit",
                "1",
            )
            self.assertEqual(code, 0, output)
            self.assertIn("event_count=1", output)
            self.assertIn("event[0].type=item.evidence_added", output)
            self.assertIn("payload_status=malformed", output)
            self.assertIn('payload_raw={"broken":', output)
            self.assertNotIn('"evidence_text":"proof one"', output)
            self.assertNotIn("item.obligation_added", output)

