            for event_id in complement_ids:
                self.assertNotIn(f"id={event_id}", bounded_requested_output)

            self.assertIn("payload_status=parsed", bounded_requested_output)
            self.assertIn("payload_status=malformed", bounded_requested_output)
            self.assertIn('payload_raw={"requested_fourth_broken":', bounded_requested_output)

