            self.assertIn("id=9c000000-0000-0000-0000-000000000010", requested_output)
            self.assertIn("payload_status=malformed", requested_output)
            self.assertIn("payload_status=parsed", requested_output)

            extracted_requested_subsequence = [event_id for event_id in full_history_ids if event_id in requested_ids]
            projected_bounded_requested = extracted_requested_subsequence[-2:]
            self.assertEqual(projected_bounded_requested, [
                "9c000000-0000-0000-0000-000000000008",
                "9c000000-0000-0000-0000-000000000010",
            ])
            rendered_requested_ids = [
                event_id for event_id in [
                    "9c000000-0000-0000-0000-000000000008",
                    "9c000000-0000-0000-0000-000000000010",
                ] if f"id={event_id}" in requested_output
            ]
            self.assertEqual(rendered_requested_ids, projected_bounded_requested)
            self.assertNotIn("id=9c000000-0000-0000-0000-000000000002", requested_output)
            self.assertNotIn("id=9c000000-0000-0000-0000-000000000004", requested_output)
            self.assertNotIn("id=9c000000-0000-0000-0000-000000000006", requested_output)
            self.assertNotIn("item.state_changed", requested_output)
            self.assertNotIn("item.obligation_added", requested_output)
            self.assertNotIn("item.contradiction_added", requested_output)

