            complement_of_bounded_requested = [event_id for event_id in full_ids if event_id not in bounded_requested_ids]

            self.assertEqual(complement_of_full_requested, [
                "a0000000-0000-0000-0000-000000000001",
                "a0000000-0000-0000-0000-000000000003",
                "a0000000-0000-0000-0000-000000000005",
                "a0000000-0000-0000-0000-000000000007",
                "a0000000-0000-0000-0000-000000000009",
                "a0000000-0000-0000-0000-000000000011",
            ])
            self.assertEqual(complement_of_bounded_requested, [
                "a0000000-0000-0000-0000-000000000001",
                "a0000000-0000-0000-0000-000000000002",
                "a0000000-0000-0000-0000-000000000003",
                "a0000000-0000-0000-0000-000000000004",
                "a0000000-0000-0000-0000-000000000005",
                "a0000000-0000-0000-0000-000000000006",
                "a0000000-0000-0000-0000-000000000007",
                "a0000000-0000-0000-0000-000000000009",
                "a0000000-0000-0000-0000-000000000011",
            ])
            self.assertEqual(
                [event_id for event_id in complement_of_bounded_requested if event_id not in complement_of_full_requested],
                ["a0000000-0000-0000-0000-000000000002", "a0000000-0000-0000-0000-000000000004", "a0000000-0000-0000-0000-000000000006"],
            )

            code, full_output = self.run_cli("--db", str(db_path), "show", item_id)
