            self.assertIn("event_count=5", requested_full_output)

            code, requested_bounded_output = self.run_cli(
                "--db", str(db_path),
                "show", item_id,
                "--event-type", "item.evidence_added",
                "--event-limit", "2",
            )
            self.assertEqual(code, 0, requested_bounded_output)
            self.assertIn("event_count=2", requested_bounded_output)

            for event_id in complement_of_full_requested:
                self.assertIn(f"id={event_id}", full_output)
                self.assertNotIn(f"id={event_id}", requested_full_output)
                self.assertNotIn(f"id={event_id}", requested_bounded_output)

            for event_id in bounded_requested_ids:
                self.assertIn(f"id={event_id}", requested_bounded_output)

            requested_added_by_unbounding = [event_id for event_id in requested_ids if event_id not in bounded_requested_ids]
            for event_id in requested_added_by_unbounding:
                self.assertIn(f"id={event_id}", requested_full_output)
                self.assertNotIn(f"id={event_id}", requested_bounded_output)
                self.assertIn(f"id={event_id}", full_output)

            self.assertIn("payload_status=malformed", requested_full_output)
            self.assertIn("payload_status=parsed", requested_full_output)
            self.assertIn("payload_status=malformed", requested_bounded_output)
            self.assertIn("payload_status=parsed", requested_bounded_output)

