            split_requested_ids = [event_id for event_id in canonical_bounded_recomposed_ids if event_id in set(requested_ids)]
            split_complement_ids = [event_id for event_id in canonical_bounded_recomposed_ids if event_id in set(complement_ids)]

            duplicate_noisy_a = split_complement_ids + split_requested_ids + [split_requested_ids[0], split_requested_ids[1], split_complement_ids[2]]
            duplicate_noisy_b = [split_requested_ids[1], split_requested_ids[1], split_complement_ids[5]] + split_requested_ids + split_complement_ids + [split_complement_ids[0], split_complement_ids[0]]
