    def test_show_event_type_and_limit_preserve_matching_malformed_event_without_crash(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"
            shutil.copy2(FIXTURES_DIR / "ace_modern_malformed_event_payload.db", db_path)
            bootstrap_db(db_path)

            with closing(self.connect_db(db_path)) as connection:
                append_event(
                    connection,
                    event_type="item.evidence_added",
                    item_id="item_event_fixture_1",
                    payload={"item_id": "item_event_fixture_1", "evidence_id": "evidence_one"},
                    actor="cli",
                )
                append_event(
                    connection,
                    event_type="item.evidence_added",
                    item_id="item_event_fixture_1",
                    payload={"item_id": "item_event_fixture_1", "evidence_id": "evidence_two"},
                    actor="cli",
                )
                connection.commit()

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "show",
                "item_event_fixture_1",
                "--event-type",
                "item.created",
                "--event-limit",
                "1",
            )
            self.assertEqual(code, 0, output)
            self.assertIn("event_count=1", output)
            self.assertIn("event[0].type=item.created", output)
            self.assertIn("event[0].payload_status=malformed", output)
            self.assertIn('event[0].payload_raw={"broken":', output)
            self.assertNotIn("item.evidence_added", output)

