            code, output = self.run_cli(
                "--db",
                str(db_path),
                "intake",
                "note",
                "Corrected claim",
                "--source",
                "telegram/direct",
                "--session",
                "telegram:7529788084:corrected-claim",
            )
            self.assertEqual(code, 0, output)
