    def test_contradiction_lifecycle_contract_from_block_to_verified_done(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "intake",
                "note",
                "Target item",
            )
            self.assertEqual(code, 0, output)
            item_id = output.split("item_id=")[1].split()[0]

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "intake",
                "note",
                "Source item",
            )
            self.assertEqual(code, 0, output)
            source_item_id = output.split("item_id=")[1].split()[0]

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "add-contradiction",
                item_id,
                source_item_id,
                "--reason",
                "conflicting evidence",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)
            contradiction_id = output.split("contradiction_id=")[1].split()[0]

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "add-evidence",
                item_id,
                "photo proof",
                "--evidence-uri",
                "file:///tmp/proof.jpg",
                "--created-by",
                "tester",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)
            evidence_id = output.split("evidence_id=")[1].split()[0]

            code, output = self.run_cli("--db", str(db_path), "approve", item_id)
            self.assertEqual(code, 0, output)
            code, output = self.run_cli("--db", str(db_path), "done", item_id)
            self.assertEqual(code, 0, output)

            code, output = self.run_cli("--db", str(db_path), "resolve", item_id, "--verdict", "pass")
            self.assertNotEqual(code, 0)
            self.assertIn("open_contradictions", output)

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "resolve-contradiction",
                contradiction_id,
                "--reason",
                "source disproved",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)
            self.assertIn("status=resolved", output)

            code, output = self.run_cli("--db", str(db_path), "resolve", item_id, "--verdict", "pass")
            self.assertEqual(code, 0, output)
            self.assertIn("state=VERIFIED_DONE", output)

            with closing(self.connect_db(db_path)) as connection:
                item_row = connection.execute(
                    "SELECT state FROM items WHERE id = ?",
                    (item_id,),
                ).fetchone()
                contradiction_row = connection.execute(
                    "SELECT status, resolved_at FROM contradictions WHERE id = ?",
                    (contradiction_id,),
                ).fetchone()
                evidence_row = connection.execute(
                    "SELECT id FROM evidence WHERE id = ? AND item_id = ?",
                    (evidence_id, item_id),
                ).fetchone()
                closeout_rows = connection.execute(
                    "SELECT result, failure_code, evidence_count, open_obligation_count FROM closeout_runs WHERE item_id = ? ORDER BY created_at ASC, id ASC",
                    (item_id,),
                ).fetchall()
                contradiction_added_events = connection.execute(
                    "SELECT COUNT(*) AS count FROM events WHERE event_type = ? AND item_id = ?",
                    ("item.contradiction_added", item_id),
                ).fetchone()["count"]
                contradiction_resolved_events = connection.execute(
                    "SELECT COUNT(*) AS count FROM events WHERE event_type = ? AND item_id = ?",
                    ("item.contradiction_resolved", item_id),
                ).fetchone()["count"]

            self.assertIsNotNone(item_row)
            self.assertEqual(item_row["state"], "VERIFIED_DONE")
            self.assertIsNotNone(contradiction_row)
            self.assertEqual(contradiction_row["status"], "resolved")
            self.assertIsNotNone(contradiction_row["resolved_at"])
            self.assertIsNotNone(evidence_row)
            self.assertEqual(contradiction_added_events, 1)
            self.assertEqual(contradiction_resolved_events, 1)
            self.assertEqual(len(closeout_rows), 2)
            self.assertEqual(closeout_rows[0]["result"], "blocked")
            self.assertEqual(closeout_rows[0]["failure_code"], "open_contradictions")
            self.assertEqual(closeout_rows[0]["evidence_count"], 1)
            self.assertEqual(closeout_rows[0]["open_obligation_count"], 0)
            self.assertEqual(closeout_rows[1]["result"], "passed")
            self.assertIsNone(closeout_rows[1]["failure_code"])
            self.assertEqual(closeout_rows[1]["evidence_count"], 1)
            self.assertEqual(closeout_rows[1]["open_obligation_count"], 0)

