    def test_resolve_obligation_second_pass_does_not_mutate_reason_or_event(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "intake",
                "note",
                "Target item",
            )
            self.assertEqual(code, 0, output)
            item_id = output.split("item_id=")[1].split()[0]

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "add-obligation",
                item_id,
                "review",
                "--status",
                "open",
                "--target-surface",
                "telegram",
                "--notes",
                "confirm receipt",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)
            obligation_id = output.split("obligation_id=")[1].split()[0]

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "resolve-obligation",
                obligation_id,
                "--reason",
                "receipt confirmed",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)

            with closing(self.connect_db(db_path)) as connection:
                first_event = connection.execute(
                    "SELECT id, payload_json FROM events WHERE event_type = ? AND item_id = ? ORDER BY created_at ASC, id ASC LIMIT 1",
                    ("item.obligation_resolved", item_id),
                ).fetchone()
                first_row = connection.execute(
                    "SELECT status, satisfied_at FROM obligations WHERE id = ?",
                    (obligation_id,),
                ).fetchone()

            self.assertIsNotNone(first_event)
            self.assertIsNotNone(first_row)
            first_payload = json.loads(first_event["payload_json"])
            self.assertEqual(first_payload["reason"], "receipt confirmed")
            self.assertEqual(first_row["status"], "resolved")
            self.assertIsNotNone(first_row["satisfied_at"])

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "resolve-obligation",
                obligation_id,
                "--reason",
                "different reason",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)
            self.assertIn("status=resolved", output)

            with closing(self.connect_db(db_path)) as connection:
                second_event_count = connection.execute(
                    "SELECT COUNT(*) AS count FROM events WHERE event_type = ? AND item_id = ?",
                    ("item.obligation_resolved", item_id),
                ).fetchone()["count"]
                same_event = connection.execute(
                    "SELECT id, payload_json FROM events WHERE event_type = ? AND item_id = ? ORDER BY created_at ASC, id ASC LIMIT 1",
                    ("item.obligation_resolved", item_id),
                ).fetchone()
                second_row = connection.execute(
                    "SELECT status, satisfied_at FROM obligations WHERE id = ?",
                    (obligation_id,),
                ).fetchone()

            self.assertEqual(second_event_count, 1)
            self.assertIsNotNone(same_event)
            self.assertEqual(same_event["id"], first_event["id"])
            self.assertEqual(json.loads(same_event["payload_json"]), first_payload)
            self.assertIsNotNone(second_row)
            self.assertEqual(second_row["status"], "resolved")
            self.assertEqual(second_row["satisfied_at"], first_row["satisfied_at"])

    def test_invalid_obligation_resolution_modes_preserve_zero_event_safety(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "intake",
                "note",
                "Target item",
            )
            self.assertEqual(code, 0, output)
            item_id = output.split("item_id=")[1].split()[0]

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "add-obligation",
                item_id,
                "review",
                "--status",
                "open",
                "--target-surface",
                "telegram",
                "--notes",
                "confirm receipt",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)
            obligation_id = output.split("obligation_id=")[1].split()[0]

            invalid_attempts = [
                (
                    [
                        "--db",
                        str(db_path),
                        "resolve-obligation",
                        obligation_id,
                        "--actor",
                        "cli",
                    ],
                    obligation_id,
                ),
                (
                    [
                        "--db",
                        str(db_path),
                        "resolve-obligation",
                        obligation_id,
                        "--reason",
                        "   ",
                        "--actor",
                        "cli",
                    ],
                    obligation_id,
                ),
                (
                    [
                        "--db",
                        str(db_path),
                        "resolve-obligation",
                        "missing-obligation",
                        "--reason",
                        "receipt confirmed",
                        "--actor",
                        "cli",
                    ],
                    None,
                ),
            ]

            for argv, expected_obligation_id in invalid_attempts:
                code, output = self.run_cli(*argv)
                self.assertNotEqual(code, 0)
                self.assertIn("error=", output)

                with closing(self.connect_db(db_path)) as connection:
                    event_count = connection.execute(
                        "SELECT COUNT(*) AS count FROM events WHERE event_type = ? AND item_id = ?",
                        ("item.obligation_resolved", item_id),
                    ).fetchone()["count"]
                    self.assertEqual(event_count, 0)

                    if expected_obligation_id is not None:
                        obligation_row = connection.execute(
                            "SELECT status, satisfied_at FROM obligations WHERE id = ?",
                            (expected_obligation_id,),
                        ).fetchone()
                        self.assertIsNotNone(obligation_row)
                        self.assertEqual(obligation_row["status"], "open")
                        self.assertIsNone(obligation_row["satisfied_at"])

    def test_bootstrap_upgrades_existing_closeout_runs_schema_with_open_contradiction_count(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"
            connection = sqlite3.connect(db_path)
            try:
                connection.execute(
                    "CREATE TABLE closeout_runs ("
                    "id TEXT PRIMARY KEY, "
                    "item_id TEXT NOT NULL, "
                    "requested_state TEXT NOT NULL, "
                    "result TEXT NOT NULL, "
                    "failure_code TEXT, "
                    "failure_detail TEXT, "
                    "evidence_count INTEGER NOT NULL DEFAULT 0, "
                    "open_obligation_count INTEGER NOT NULL DEFAULT 0, "
                    "created_at TEXT NOT NULL, "
                    "completed_at TEXT"
                    ")"
                )
                connection.commit()
            finally:
                connection.close()

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "list",
            )
            self.assertEqual(code, 0, output)

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "intake",
                "note",
                "Migrated item",
            )
            self.assertEqual(code, 0, output)
            item_id = output.split("item_id=")[1].split()[0]

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "add-evidence",
                item_id,
                "proof",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "approve",
                item_id,
            )
            self.assertEqual(code, 0, output)

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "done",
                item_id,
            )
            self.assertEqual(code, 0, output)

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "resolve",
                item_id,
                "--verdict",
                "pass",
            )
            self.assertEqual(code, 0, output)
            self.assertIn("state=VERIFIED_DONE", output)

            with closing(self.connect_db(db_path)) as connection:
                columns = connection.execute("PRAGMA table_info(closeout_runs)").fetchall()
                latest_closeout = connection.execute(
                    "SELECT result, failure_code, open_contradiction_count FROM closeout_runs WHERE item_id = ? ORDER BY created_at DESC, id DESC LIMIT 1",
                    (item_id,),
                ).fetchone()

            column_names = [column["name"] for column in columns]
            self.assertIn("open_contradiction_count", column_names)
            self.assertIsNotNone(latest_closeout)
            self.assertEqual(latest_closeout["result"], "passed")
            self.assertIsNone(latest_closeout["failure_code"])
            self.assertEqual(latest_closeout["open_contradiction_count"], 0)


