            self.assertEqual(code, 0, output)
            code, output = self.run_cli("--db", str(db_path), "done", closeout_id, "--reason", "ready to close")
            self.assertEqual(code, 0, output)
            code, output = self.run_cli("--db", str(db_path), "resolve", closeout_id, "--verdict", "pass", "--reason", "close it")
            self.assertEqual(code, 0, output)
            self.assertIn("state=VERIFIED_DONE", output)

            code, list_output = self.run_cli("--db", str(db_path), "list")
            self.assertEqual(code, 0, list_output)
            expected_lines = {
                triage_drop_id: "item_id=%s state=DROPPED title=triage branch" % triage_drop_id,
                approved_done_id: "item_id=%s state=CLAIMED_DONE title=approved branch" % approved_done_id,
                blocked_resolve_id: "item_id=%s state=APPROVED title=blocked branch" % blocked_resolve_id,
                closeout_id: "item_id=%s state=VERIFIED_DONE title=closeout branch" % closeout_id,
            }
            for line in expected_lines.values():
                self.assertIn(line, list_output)

            with closing(self.connect_db(db_path)) as connection:
                rows = connection.execute(
                    "SELECT id, state, last_event_id FROM items ORDER BY created_at ASC, id ASC"
                ).fetchall()
                closeout_runs = connection.execute(
                    "SELECT item_id, result, failure_code FROM closeout_runs ORDER BY id ASC"
                ).fetchall()

            self.assertEqual(
                [dict(row) for row in rows],
                [
                    {"id": triage_drop_id, "state": "DROPPED", "last_event_id": rows[0]["last_event_id"]},
                    {"id": approved_done_id, "state": "CLAIMED_DONE", "last_event_id": rows[1]["last_event_id"]},
                    {"id": blocked_resolve_id, "state": "APPROVED", "last_event_id": rows[2]["last_event_id"]},
                    {"id": closeout_id, "state": "VERIFIED_DONE", "last_event_id": rows[3]["last_event_id"]},
                ],
            )
            self.assertEqual(
                [dict(row) for row in closeout_runs],
                [{"item_id": closeout_id, "result": "passed", "failure_code": None}],
            )

