            code, output = self.run_cli("--db", str(db_path), "resolve", closeout_id, "--verdict", "pass", "--reason", "close it")
            self.assertEqual(code, 0, output)
            self.assertIn("state=VERIFIED_DONE", output)

            with closing(self.connect_db(db_path)) as connection:
                closeout_rows = connection.execute(
                    "SELECT item_id, result, failure_code FROM closeout_runs ORDER BY id ASC"
                ).fetchall()
                event_counts = {
                    item_id: connection.execute(
                        "SELECT COUNT(*) AS count FROM events WHERE item_id = ? AND event_type = 'item.closeout_attempted'",
                        (item_id,),
                    ).fetchone()["count"]
                    for item_id in (dropped_id, blocked_id, claimed_id, closeout_id)
                }

            self.assertEqual(
                [dict(row) for row in closeout_rows],
                [{"item_id": closeout_id, "result": "passed", "failure_code": None}],
            )
            self.assertEqual(
                event_counts,
                {
                    dropped_id: 0,
                    blocked_id: 0,
                    claimed_id: 0,
                    closeout_id: 1,
                },
            )

            for item_id, expected_state in (
                (dropped_id, "DROPPED"),
                (blocked_id, "BLOCKED"),
                (claimed_id, "CLAIMED_DONE"),
                (closeout_id, "VERIFIED_DONE"),
            ):
                code, show_output = self.run_cli("--db", str(db_path), "show", item_id, "--event-limit", "10")
                self.assertEqual(code, 0, show_output)
                self.assertIn(f"state={expected_state}", show_output)
                if item_id == closeout_id:
                    self.assertIn("type=item.closeout_attempted", show_output)
                    self.assertIn('"result":"passed"', show_output)
                else:
                    self.assertNotIn("type=item.closeout_attempted", show_output)
                    self.assertNotIn('"result":"passed"', show_output)
                    self.assertNotIn('"failure_code":', show_output)

