            self.assertEqual(code, 0, output)
            code, output = self.run_cli("--db", str(db_path), "done", blocked_id, "--reason", "ready blocked")
            self.assertEqual(code, 0, output)
            code, blocked_resolve_output = self.run_cli("--db", str(db_path), "resolve", blocked_id, "--reason", "blocked closeout")
            self.assertEqual(code, 1, blocked_resolve_output)
            self.assertIn("open_obligations", blocked_resolve_output)

            code, output = self.run_cli("--db", str(db_path), "intake", "task", "Dropped item")
