    def test_mixed_lifecycle_keeps_item_truth_event_truth_and_last_event_id_in_sync(self) -> None:
        with tempfile.TemporaryDirectory() as tmpdir:
            db_path = Path(tmpdir) / "ace.db"

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "intake",
                "note",
                "Lifecycle parity item",
                "--source",
                "telegram",
                "--session",
                "telegram:7529788084",
            )
            self.assertEqual(code, 0, output)
            item_id = output.split("item_id=")[1].split()[0]

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "add-evidence",
                item_id,
                "photo proof",
                "--evidence-uri",
                "file:///tmp/proof.jpg",
                "--created-by",
                "tester",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "add-obligation",
                item_id,
                "review",
                "--status",
                "open",
                "--target-surface",
                "telegram",
                "--notes",
                "confirm receipt",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)
            obligation_id = output.split("obligation_id=")[1].split()[0]

            for action, reason, expected_state in (
                ("approve", "initial approve", "APPROVED"),
                ("done", "ready for closeout", "CLAIMED_DONE"),
                ("block", "needs review", "BLOCKED"),
                ("resolve", "review complete", "APPROVED"),
                ("done", "ready again", "CLAIMED_DONE"),
            ):
                code, output = self.run_cli("--db", str(db_path), action, item_id, "--reason", reason)
                self.assertEqual(code, 0, output)
                self.assertIn(f"state={expected_state}", output)

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "resolve-obligation",
                obligation_id,
                "--reason",
                "confirmed",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)

            code, output = self.run_cli("--db", str(db_path), "resolve", item_id, "--verdict", "pass", "--reason", "close it")
            self.assertEqual(code, 0, output)
            self.assertIn("state=VERIFIED_DONE", output)

            with closing(self.connect_db(db_path)) as connection:
                item_row = connection.execute(
                    "SELECT state, last_event_id FROM items WHERE id = ?",
                    (item_id,),
                ).fetchone()
                event_rows = connection.execute(
                    "SELECT event_id, event_type, payload_json FROM events WHERE item_id = ? ORDER BY created_at ASC, id ASC",
                    (item_id,),
                ).fetchall()

            self.assertEqual(item_row["state"], "VERIFIED_DONE")
            self.assertGreater(len(event_rows), 0)
            self.assertEqual(item_row["last_event_id"], event_rows[-1]["event_id"])

            event_types = [row["event_type"] for row in event_rows]
            self.assertEqual(
                event_types,
                [
                    "item.created",
                    "item.evidence_added",
                    "item.obligation_added",
                    "item.state_changed",
                    "item.state_changed",
                    "item.state_changed",
                    "item.state_changed",
                    "item.state_changed",
                    "item.obligation_resolved",
                    "item.verdict_recorded",
                    "item.closeout_attempted",
                    "item.state_changed",
                ],
            )

            last_payload = json.loads(event_rows[-1]["payload_json"])
            self.assertEqual(last_payload["action"], "resolve")
            self.assertEqual(last_payload["from_state"], "CLAIMED_DONE")
            self.assertEqual(last_payload["to_state"], "VERIFIED_DONE")
            self.assertEqual(last_payload["item_id"], item_id)
            self.assertEqual(item_row["state"], last_payload["to_state"])

