            self.assertIn("state=APPROVED", output)

            code, output = self.run_cli("--db", str(db_path), "done", item_id, "--reason", "ready for closeout")
            self.assertEqual(code, 0, output)
            self.assertIn("state=CLAIMED_DONE", output)

            code, output = self.run_cli("--db", str(db_path), "block", item_id, "--reason", "needs review")
            self.assertEqual(code, 0, output)
            self.assertIn("state=BLOCKED", output)

            code, output = self.run_cli("--db", str(db_path), "resolve", item_id, "--verdict", "pass", "--reason", "review complete")
            self.assertEqual(code, 0, output)
            self.assertIn("state=APPROVED", output)

            code, output = self.run_cli("--db", str(db_path), "done", item_id, "--reason", "ready again")
            self.assertEqual(code, 0, output)
            self.assertIn("state=CLAIMED_DONE", output)

            code, output = self.run_cli(
                "--db",
                str(db_path),
                "add-evidence",
                item_id,
                "photo proof",
                "--evidence-uri",
                "file:///tmp/proof.jpg",
                "--created-by",
                "tester",
                "--actor",
                "cli",
            )
            self.assertEqual(code, 0, output)

            code, output = self.run_cli("--db", str(db_path), "resolve", item_id, "--verdict", "pass", "--reason", "close it")
            self.assertEqual(code, 0, output)
            self.assertIn("state=VERIFIED_DONE", output)

            with closing(self.connect_db(db_path)) as connection:
                item_row = connection.execute(
                    "SELECT state, last_event_id FROM items WHERE id = ?",
                    (item_id,),
                ).fetchone()
                state_changed_rows = connection.execute(
                    "SELECT payload_json FROM events WHERE item_id = ? AND event_type = ? ORDER BY created_at ASC, id ASC",
                    (item_id, "item.state_changed"),
                ).fetchall()
                closeout_rows = connection.execute(
                    "SELECT result, failure_code, evidence_count, open_obligation_count, open_contradiction_count FROM closeout_runs WHERE item_id = ? ORDER BY created_at ASC, id ASC",
                    (item_id,),
                ).fetchall()

            self.assertEqual(item_row["state"], "VERIFIED_DONE")
            payloads = [json.loads(row["payload_json"]) for row in state_changed_rows]
            self.assertEqual(
                [(p["action"], p["from_state"], p["to_state"], p.get("reason")) for p in payloads],
                [
                    ("approve", "TRIAGE", "APPROVED", "initial approve"),
                    ("done", "APPROVED", "CLAIMED_DONE", "ready for closeout"),
                    ("block", "CLAIMED_DONE", "BLOCKED", "needs review"),
                    ("resolve", "BLOCKED", "APPROVED", "review complete"),
                    ("done", "APPROVED", "CLAIMED_DONE", "ready again"),
                    ("resolve", "CLAIMED_DONE", "VERIFIED_DONE", "close it"),
                ],
            )
            self.assertEqual(len(closeout_rows), 1)
            self.assertEqual(closeout_rows[0]["result"], "passed")
            self.assertIsNone(closeout_rows[0]["failure_code"])
            self.assertEqual(closeout_rows[0]["evidence_count"], 1)
            self.assertEqual(closeout_rows[0]["open_obligation_count"], 0)
            self.assertEqual(closeout_rows[0]["open_contradiction_count"], 0)

        
